issues.suggested_fix:
Use `use std::collections::hash_map::Entry;` and:
```rust
for (i, t) in templates.iter().enumerate() {
    match name_to_idx.entry(t.name.as_str()) {
        Entry::Occupied(e) => {
            let prev_idx = *e.get();
            diagnostics.push(reify_types::Diagnostic::error(format!(
                "internal compiler error: duplicate template name '{}' reached SCC pass (first at index {}, duplicate at index {})",
                t.name, prev_idx, i
            )));
        }
        Entry::Vacant(v) => { v.insert(i); }
    }
}
```
